import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const B=JSON.parse('{"title":"武装龙","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/武装龙.md","filePath":"4.资源分区/1.血统与训练/5.通用类/武装龙.md"}'),s={name:"4.资源分区/1.血统与训练/5.通用类/武装龙.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"武装龙",tabindex:"-1"},[t("武装龙 "),r("a",{class:"header-anchor",href:"#武装龙","aria-label":'Permalink to "武装龙"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),n('<h1 id="武装龙-1" tabindex="-1">武装龙 <a class="header-anchor" href="#武装龙-1" aria-label="Permalink to &quot;武装龙&quot;">​</a></h1><p>【武装龙】血统<br> 同时结合了【游戏王】和【影之诗】两种卡牌游戏里的【武装龙】系列怪兽，此外还包含一些相关能形成配合的卡的能力</p><p>【武装龙Lv3】<br> D+600<br> 你从外观上变为一只橙红色的直立型无翼幼龙（体积不变），身上附着些许装甲，种族在需要判定时可以视作龙族（与原种族取劣），这是一种外观上的变化，不具备额外的增益效果。<br> 拥有此血统后，你获得【龙之武装】特性。</p><p>【龙之武装】：<br> 你习得了一种创造临时装备的能力。每轮一次，以一个标准动作发动，你创造出【1】个特殊装备【龙武装甲】，并将其装备给自身。<br> 以此方法创造的【龙武装甲】至多可以持续一个场景，超时或脱下后自动消失。<br> 当你同时持用多个【龙武装甲】变形成的武器时，你在攻击时可以武器伤害取高、攻击范围取低，在攻击时获得加入攻击武器除基本属性外的特性。</p><p>在使用标准动作创造【龙武装甲】后，你可以立刻使用【龙武装甲】进行一次不能附带任何招式的普通攻击；若你没有能用来攻击的【龙武装甲】，则无法发动这一效果。</p><p>【龙武装甲】：<br> 装备外观：外观上为一把叠加了剑刃与甲胄的长矛，可以装备在任意未被占据的武器/护甲位（同一位置只能装备一个），装备后自动变形并适配着装者体型。<br> 装备效果：根据你选择的装备位置获得不同效果。<br> ①武器位：装备时选定一种现实近战武器，【龙武装甲】变形为同类的基础武器（该武器选定后无法更改，但可脱下该武器并装备新的【龙武装甲】来重新选择），并且额外获得【破甲5】，因此获得的破防属性独立计算，不属于武器基本属性与特性，无法多次叠加。<br> ②护甲位：购买时选择其视为轻甲或重甲，一经选择无法改变，装备后提供盔甲防御6/6，无法进行多层护甲。<br> 装备者可以用一个自由动作脱下所有【龙武装甲】。</p><p>【武装龙Lv5】<br> C+1200<br> 你的体型增大，并且背后长出了一对小翅膀，这使你获得普通飞行能力。<br> 血统到达该等级后，你获得【攻守兼备】、【武装解除】特性。</p><p>【攻守兼备】：<br> 你制造装备的能力更加娴熟，进攻和防御都可以兼顾，从现在开始，【龙武装甲】的效果在制造武器后，也能同时使你获得上述中护甲位提供的效果（正常占用护甲位置，龙武装甲无法进行多层护甲），并且护甲提供的盔甲防御提升至10/10；这也会使你每轮只能使用一次标准动作来制作【龙武装甲】。</p><p>表现为你可以用手上的武器增强防御，或者身上的装备变形延展攻击。</p><p>【武装解除】：<br> 在你装备上【龙武装甲】的时候，你可以选择让其进入【武装解除】状态以解放力量，提高敏捷性；这一状态持续时间为一场景/直到你使用自由动作解除，生效期间你无法获得【龙武装甲】提供的效果。</p><p>根据你处于【武装解除】状态的【龙武装甲】数目，你依次获得以下效果<br> 1个：你使用【龙武装甲】武器进行冲锋攻击时，基础防御不承受减值。<br> 2个：你使用【龙武装甲】武器进行冲锋攻击的移动行为结束后，即使攻击目标离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击。<br> 3个：你使用【龙武装甲】武器进行冲锋攻击时，有效距离取最大值计算。</p><p>【武装龙Lv7】<br> B+2400<br> 你的体型进一步增大，身形也变得健美而挺拔。<br> 血统到达该等级后，你获得【示天龙剑】特性。</p><p>【示天龙剑】：<br> 在与你创造的【龙武装甲】朝夕相处、并肩作战中，你逐渐与装甲融为一体，并可以调整装甲的特性来获得不同的强化效果。<br> 当你装备上【龙武装甲】时，可以从以下形态中选择一个变身并获得相应效果，持续一个场景。当你再次装备【龙武装甲】时可以切换形态，同一时间你只能获得其中一个形态的效果<br> ①进攻模式：你额外获得4点AP，仅可用于转化为使用【龙武装甲】武器进行攻击的动作。<br> ②防御模式：你获得2点【全伤害吸收】，基于盔甲防御；你获得【快速医疗2：医疗点数24】（医疗点不会随着切换形态而刷新）。<br> ③爆破模式：你使用【龙武装甲】进行攻击造成伤害时，你可以将至多【7】点严重伤害转变为韧性伤害</p><p>【武装龙Lv10】<br> A+4800<br> 这是武装龙进化的最终阶段，拥有强韧的身躯和豪迈的力量，能够灵活操纵全身的武器。<br> 血统到达该等级后，你获得【全副武装】、【多极盛怒】特性。</p><p>【多极盛怒】：<br> 取代B级的【示天龙剑】效果，现在你常驻获得三个模式的全部效果；每轮一次，若你对使用龙武装甲变形的武器进行攻击出目不满意，则可以进行一次重骰，但必须接受第二次结果。</p><p>【全副武装】：<br> 在你在同一场景中使用标准动作获得龙武装甲后，每轮开始时你都会无需动作的再装备一次龙武装甲提供的武器，这些武器会正常占用你的装备位；你可以在未使用每轮开始时额外获得的龙武装甲武器攻击时，将这些武器基础属性一半与所有特性加入攻击。</p><p>龙武装甲作为武器使用时，之前等级提供的破防能力改为：额外获得【25】点破甲，与高速/破魔/威猛各【5】点，并且这些破防属性结算目标防御后若仍有剩余，则这些剩余破防属性转化为攻击上的器械加值；因此提供的破防属性独立计算，不视为武器具有的基本属性与特性，因此无法多次叠加处理。</p><p>专属技艺<br> 以下技艺必须在你至少拥有同级血统的时候才可以购买，低等级血统无法购买高等级技艺。</p><p>【武装龙的霹雳】<br> D+500<br> 武装龙对雷电能量有着较高的适应性，你开始尝试将其注入你的武器，你的【龙武装甲】武器获得【法破】特性<br> 你获得一种特殊移动方式。在非战斗场景下，你可以进行一次十分钟到1小时的蓄力（具体蓄力时间视移动距离而定），而后化作一道雷霆射入空中，再落下到你要移动的目标地点。<br> 以此方法可以在一小时内从城市的一端至另一端，也可以在一小时内从一座城市抵达另一座相邻城市，这是一个D级时空来源的【旅行】效果。</p><p>【武装龙的袭雷】<br> C+1000<br> 前置：【武装龙的霹雳】<br> 你的【龙武装甲】武器充斥雷电能量，获得【能量武器】特性。并且由于雷电能量赋予的磁力，武装会自动悬浮吸附在你身上，这使你免疫【击落武器】效果。</p><p>【武装龙的震霆】<br> B+2000<br> 前置：【武装龙的袭雷】<br> 你使用【龙武装甲】武器攻击时，雷电能量可以从武器身上延伸发射，使这些武器的攻击触及距离提升60m。<br> 当你死亡时，你可以转为一朵雷云漂浮在遗体上空，该状态下你除了观察和移动外无法进行更多的动作，经过一个月的时间后可以复活。<br> 雷云态下你具有等同于你意志值的结构值，若被破坏则复活失败。这是一个B级时空来源的【复活】效果。</p><p>【武装龙的万雷】：<br> A+4000<br> 前置：【武装龙的震霆】<br> 你的身躯和雷电融为一体，当你进行移动时会化作电光穿透各种障碍，这是一个B级【传送移动】效果<br> 你创造的装备也彻底和雷电能量融合，你现在使用【龙武装甲】武器进行的攻击可以附带等同伤害出目的【麻痹】不良点数，正常豁免；你进行的攻击具有B级【传送攻击】效果，伤害类型可以转为【雷电】能量伤害。<br> 此外，你可以吸收战场上已死亡的单位的电能量，你具有【生息】特性。</p><p>【铠骑士武装】<br> C+1500<br> 你学习了如何强化装备的防御性能，获得这一能力并经过一次影片后，你从C级龙武装甲中获得的盔甲防御提升至18/18，并获得基于盔甲防御的防弹、防能量武器；在那之后，每场影片结束后，你创造的每件【龙武装甲】提供的盔甲防御会提高【1】点。</p><p>【冲击钻武装】<br> B+2000<br> 你学会了在装备上增加旋转结构以增强攻击力，每场影片后，你创造的每一件【龙武装甲】武器的武器伤害提高【1】点；在处理将未使用的【龙武装甲】武器一半基础属性与特性加入攻击的效果时，这一能力只会计算一次而非多次。<br> 同时因为你身上武器的威慑力，敌人往往会有所退缩，你的先攻提升10点。</p><p>【魔化/玄化武装】<br> B+2000<br> 购买此技艺后，你可以选择转变为【暗黑生物】或【光明生物】之一。当你已是【暗黑生物】或【光明生物】，并选择转变为另一类时，你将同时视作【暗黑生物】和【光明生物】，并且在需要进行判定时取劣势效果。<br> 当你为【暗黑生物】时，你获得【魔化武装】特性：你使用【龙武装甲】武器的攻击附带B级【重伤】效果。<br> 当你为【光明生物】时，你获得【玄化武装】特性：你使用【龙武装甲】武器攻击命中对手后，对手以意志豁免对抗你的伤害出目，若对抗失败则被你放逐至异空间一轮。这是一个B级时空来源的【放逐】效果。</p><p>【白之衣武装】<br> B+2000<br> 购买此技艺后，你的全身将覆盖能够隔绝魔法与陷阱效果的白色轻纱（你可以理解为全身白丝）<br> 你免疫A级以下由魔力驱动的效果影响。<br> 每轮一次，你的三豁免检定之一可以重新投掷并取更高的结果，无论如何此效果一回合只能让你的三豁免之一重骰取高。</p><p>【同盟武装】<br> B+2000<br> 习得此技艺后，你的【龙武装甲】可以变形为更加独特的【同盟装备】。<br> 购买后选择以下五种武装之一，当你装备一件【龙武装甲】时，你可以选择让其获得对应的效果；一件【龙武装甲】只能获得以下的一种效果；若需要处理来源，均视为B级创伤来源。<br> 你可以重复购买此项直到你的装备的5件【龙武装甲】各获得以下的一种效果。<br> ①V-喷气机虎：你可以让一件【龙武装甲】增加喷气结构，极大程度增强武装的推动力。这使得该武器获得【超级贯穿】和【接触攻击】效果。</p><p>②W-弹射飞翼：你可以让一件【龙武装甲】增加弹射结构，攻击时可以在近距离再次造成冲击。这使得该武器获得【余波】效果；使用该武器进行的攻击命中后，目标采用反射豁免对抗伤害出目，失败则被击飞差值/米，这是一个B级击飞效果（正常具有B级击飞的其他效果），因击飞效果结束后计算坠落伤害的距离时，按照60米计算。</p><p>③X-首领加农：你可以让一件【龙武装甲】增加炮管结构，攻击时附带炮火轰击。该武器变为对触及距离内所有敌人造成伤害，可以改为使敌人进行反射豁免而非正常防御该武器进行的攻击，并且具有【湮灭】特性。</p><p>④Y-机械飞龙：你可以让一件【龙武装甲】增加龙头结构，龙头形象会震慑对手。这使得你获得【威仪】效果，并且该武器在攻击时附带伤害出目四分之一的【恐惧】和【精神束缚】不良点数，正常豁免。</p><p>⑤Z-金属履带：你可以让一件【龙武装甲】增加履带结构，可以在任何地面自由移动。这使得你在装备状态下获得免疫不超过B级环境来源效果影响都能力，同时获得等同于移动速度的游泳和遁地速度（遁力0），并且使用该武器攻击时获得【碾压】效果；你可以额外支付D+500，使遁地速度的盾力提升至6，这一额外支付视为进行了一个D级技艺的购买。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',33)])])}const f=p(s,[["render",o]]);export{B as __pageData,f as default};
